-- Migration: 0024_seasonal_produce_seed
-- Purpose: Seed seasonal_produce (added in 0023) with real, cited monthly calendars for the 8
-- Tier-1 countries. Generated from apps/api/src/memory/seasonal-produce-data.ts (the canonical
-- TS source — keep both in sync if either changes; see that file's header comment).
-- Singapore (SG) is intentionally absent: >90% of its food is imported (Singapore Food Agency)
-- and there is no meaningful domestic seasonal calendar to cite — an empty result for SG is the
-- honest answer, not a gap to fill with invented data.
-- Rollback: see 0024_seasonal_produce_seed_rollback.sql

BEGIN;

ON CONFLICT (country_code, COALESCE(region, ''), month) DO UPDATE SET items = EXCLUDED.items, source = EXCLUDED.source;

COMMIT;
